// Code generated by hand for performance.
// SPDX-License-Identifier: Apache-2.0
//
// NEON 2D pooling row drivers. Each call processes 4 contiguous output
// columns for one (batch, channel, output row) triple — the inner
// kernel-window loop uses FMAX (max pool) or FADD (avg pool) on .4S
// against contiguous input rows.
//
// Caller computes startRow/startCol per output row; valid for any
// stride and padding (the input pointer + offsets handle it).
// Bounds clipping (for padding) is the caller's responsibility — the
// asm does not test row/col bounds in the inner loop.

#include "textflag.h"

#define VFADD_S4(m, n, d) WORD $(0x4E20D400 | ((m) << 16) | ((n) << 5) | (d))
#define VFMAX_S4(m, n, d) WORD $(0x4E20F400 | ((m) << 16) | ((n) << 5) | (d))
#define VFMUL_S4(m, n, d) WORD $(0x6E20DC00 | ((m) << 16) | ((n) << 5) | (d))

// func maxPool2DStride1RowNEONAsm(
//     outRow *float32, input *float32,
//     outCols, kH, kW int,
//     inHStride int,   // input width (bytes pre-scale)
//     ihStart int,     // anchor input row for this output row
// )
TEXT ·maxPool2DStride1RowNEONAsm(SB), NOSPLIT, $0-56
    MOVD outRow+0(FP), R0
    MOVD input+8(FP), R1
    MOVD outCols+16(FP), R2
    MOVD kH+24(FP), R3
    MOVD kW+32(FP), R4
    MOVD inHStride+40(FP), R5
    MOVD ihStart+48(FP), R6

    LSL  $2, R5, R5                // byte stride
    MUL  R5, R6, R6
    ADD  R6, R1, R1                // anchor pointer

    // Initialize "running max" to -inf — bit pattern 0xFF800000.
    MOVD $0xFF800000, R7
    VMOV R7, V31.S[0]
    VDUP V31.S[0], V31.S4

mp_col_loop:
    CMP  $4, R2
    BLT  mp_done
    // V0 = -inf accumulator.
    WORD $(0x4EA01C00 | (31 << 16) | (31 << 5) | 0)  // VMOV V31, V0

    MOVD R3, R8                    // remaining kH
    MOVD R1, R9                    // input row pointer

mp_kh_loop:
    CBZ  R8, mp_kh_done
    MOVD R4, R10                   // remaining kW
    MOVD R9, R11                   // input col pointer

mp_kw_loop:
    CBZ  R10, mp_kw_done
    VLD1 (R11), [V1.S4]            // 4 contiguous floats at this kernel position
    VFMAX_S4(1, 0, 0)              // V0 = max(V0, V1)
    ADD  $4, R11                   // kw column advance
    SUB  $1, R10
    B    mp_kw_loop

mp_kw_done:
    ADD  R5, R9, R9                // next kernel row
    SUB  $1, R8
    B    mp_kh_loop

mp_kh_done:
    VST1 [V0.S4], (R0)
    ADD  $16, R0
    ADD  $16, R1                   // anchor moves by 4 cols (stride=1)
    SUB  $4, R2
    B    mp_col_loop

mp_done:
    RET

// func avgPool2DStride1RowNEONAsm(
//     outRow *float32, input *float32,
//     outCols, kH, kW int,
//     inHStride int,
//     ihStart int,
// )
// Computes sum over the kernel window then multiplies by 1/(kH*kW).
TEXT ·avgPool2DStride1RowNEONAsm(SB), NOSPLIT, $0-56
    MOVD outRow+0(FP), R0
    MOVD input+8(FP), R1
    MOVD outCols+16(FP), R2
    MOVD kH+24(FP), R3
    MOVD kW+32(FP), R4
    MOVD inHStride+40(FP), R5
    MOVD ihStart+48(FP), R6

    LSL  $2, R5, R5
    MUL  R5, R6, R6
    ADD  R6, R1, R1

    // 1 / (kH * kW) as broadcast in V31.
    MUL  R4, R3, R12
    SCVTFWS R12, F31
    // Reciprocal via FDIV: V31 = 1.0 / V31.
    MOVD $0x3F800000, R7
    VMOV R7, V30.S[0]              // 1.0 bits
    VDUP V30.S[0], V30.S4
    VDUP V31.S[0], V31.S4
    // V29 = 1.0 / V31
    WORD $(0x6E20FC00 | (31 << 16) | (30 << 5) | 29)  // VFDIV V31, V30, V29

ap_col_loop:
    CMP  $4, R2
    BLT  ap_done
    // V0 = 0 accumulator.
    VEOR V0.B16, V0.B16, V0.B16

    MOVD R3, R8
    MOVD R1, R9

ap_kh_loop:
    CBZ  R8, ap_kh_done
    MOVD R4, R10
    MOVD R9, R11

ap_kw_loop:
    CBZ  R10, ap_kw_done
    VLD1 (R11), [V1.S4]
    VFADD_S4(1, 0, 0)
    ADD  $4, R11
    SUB  $1, R10
    B    ap_kw_loop

ap_kw_done:
    ADD  R5, R9, R9
    SUB  $1, R8
    B    ap_kh_loop

ap_kh_done:
    // V0 *= 1/(kH*kW)
    VFMUL_S4(29, 0, 0)
    VST1 [V0.S4], (R0)
    ADD  $16, R0
    ADD  $16, R1
    SUB  $4, R2
    B    ap_col_loop

ap_done:
    RET
